# Verify we can build a standalone Go program with ICMP via syscall
cat > /tmp/ping_test.go <<'EOF'
package main

import (
	"encoding/binary"
	"fmt"
	"net"
	"os"
	"syscall"
	"time"
)

func icmpChecksum(b []byte) uint16 {
	var s uint32
	for i := 0; i+1 < len(b); i += 2 {
		s += uint32(b[i])<<8 | uint32(b[i+1])
	}
	if len(b)%2 == 1 {
		s += uint32(b[len(b)-1]) << 8
	}
	for s>>16 != 0 {
		s = (s & 0xffff) + (s >> 16)
	}
	return ^uint16(s)
}

func main() {
	host := "127.0.0.1"
	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	// Resolve
	ips, err := net.LookupIP(host)
	if err != nil {
		fmt.Printf("resolve err: %v\n", err)
		return
	}
	var ip4 net.IP
	for _, ip := range ips {
		if ip4 = ip.To4(); ip4 != nil {
			break
		}
	}
	fmt.Printf("Resolved to %v\n", ip4)

	// Open SOCK_DGRAM ICMP
	fd, err := syscall.Socket(syscall.AF_INET, syscall.SOCK_DGRAM, 1) // IPPROTO_ICMP
	if err != nil {
		fmt.Printf("socket err: %v\n", err)
		return
	}
	defer syscall.Close(fd)

	// Set TTL receive option
	syscall.SetsockoptInt(fd, syscall.IPPROTO_IP, syscall.IP_TTL, 64)
	// IP_RECVTTL  = 12 (on linux)
	syscall.SetsockoptInt(fd, syscall.IPPROTO_IP, 12, 1)

	// Build ICMP echo request
	payload := make([]byte, 24)
	for i := range payload {
		payload[i] = byte(i)
	}
	// Add timestamp to payload (first 8 bytes)
	now := time.Now().UnixNano()
	binary.BigEndian.PutUint64(payload[:8], uint64(now))

	pkt := make([]byte, 8+len(payload))
	pkt[0] = 8 // echo request
	pkt[1] = 0
	pkt[4] = 0  // id (kernel fills)
	pkt[5] = 0
	pkt[6] = 0  // seq
	pkt[7] = 0
	copy(pkt[8:], payload)
	cs := icmpChecksum(pkt)
	pkt[2] = byte(cs >> 8)
	pkt[3] = byte(cs)

	var dst [4]byte
	copy(dst[:], ip4)
	sa := &syscall.SockaddrInet4{Port: 0, Addr: dst}

	send := time.Now()
	if err := syscall.Sendto(fd, pkt, 0, sa); err != nil {
		fmt.Printf("sendto err: %v\n", err)
		return
	}

	// Receive
	buf := make([]byte, 1500)
	n, _, err := syscall.Recvfrom(fd, buf, 0)
	if err != nil {
		fmt.Printf("recvfrom err: %v\n", err)
		return
	}
	rtt := time.Since(send)
	fmt.Printf("Received %d bytes, rtt=%v\n", n, rtt)
	fmt.Printf("ICMP type=%d code=%d\n", buf[0], buf[1])

	// Try cmsg with recvmsg to get TTL
	buf2 := make([]byte, 1500)
	oob := make([]byte, 64)
	syscall.Sendto(fd, pkt, 0, sa)
	n2, oobn, _, _, err := syscall.Recvmsg(fd, buf2, oob, 0)
	fmt.Printf("Recvmsg n=%d oobn=%d err=%v\n", n2, oobn, err)
	cmsgs, err := syscall.ParseSocketControlMessage(oob[:oobn])
	for _, m := range cmsgs {
		fmt.Printf("cmsg level=%d type=%d data=%v\n", m.Header.Level, m.Header.Type, m.Data)
	}
}
EOF
