}

func run() int {
	flags, err := parseArgs(os.Args[1:])

	if flags.help {
		os.Stdout.WriteString(helpText)
		return 0
	}
	if err != nil {
		var pe *flagParseError
		if errors.As(err, &pe) {
			fmt.Fprintln(os.Stderr, pe.msg)
			fmt.Fprintf(os.Stderr, "[ ERROR ] parse error: %s\n", pe.msg)
			return 1
		}
		fmt.Fprintf(os.Stderr, "[ ERROR ] %s\n", err)
